1	export type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	export type Step = { op: "quote"; items: Item[] };
3	export type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	export type ScenarioResult = { results: Array<{ premium: number }> };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const COMPONENT_UNIT_BASE = 25;
10	const COMPONENT_BLOCK_SIZE = 3;
11	const COMPONENT_BLOCK_BASE = 60;
12	
13	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
23	
24	// A billing group is one main item or one bundle of alike components.
25	// `cursed` only applies to main items.
26	type BillingGroup = { base: number; cursed: boolean };
27	
28	const componentBundleBase = (count: number): number => {
29	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_BASE;
30	  return count * COMPONENT_UNIT_BASE;
31	};
32	
33	const billingGroups = (items: Item[]): BillingGroup[] => {
34	  const groups: BillingGroup[] = [];
35	  const componentCounts = new Map<string, number>();
36	  for (const item of items) {
37	    if (isComponent(item)) {
38	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
39	    } else {
40	      groups.push({ base: MAIN_ITEM_BASE_PREMIUM[item.type], cursed: item.cursed === true });
41	    }
42	  }
43	  for (const count of componentCounts.values()) {
44	    groups.push({ base: componentBundleBase(count), cursed: false });
45	  }
46	  return groups;
47	};
48	
49	const groupPremium = (group: BillingGroup): number => {
50	  const curseSurcharge = group.cursed ? group.base * CURSE_SURCHARGE_RATE : 0;
51	  const firstInsurance = group.base * FIRST_INSURANCE_RATE;
52	  return group.base + curseSurcharge + firstInsurance;
53	};
54	
55	const quotePremium = (items: Item[]): number => {
56	  const itemsTotal = billingGroups(items).reduce((sum, g) => sum + groupPremium(g), 0);
57	  return Math.ceil(itemsTotal + PROCESSING_FEE);
58	};
59	
60	export const runScenario = (scenario: Scenario): ScenarioResult => {
61	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
62	  return { results };
63	};
